select t.template_id,t.template_name,t.description,t.owner_id,u.user_name,t.create_time,t.columns_value
from tfp_column_template t,nrmdb.tau_user u
where u.user_id=t.owner_id and template_id=#{id}


select t.template_id,t.template_name,t.description,t.owner_id,u.user_name,t.create_time,t.status_value
from Tfp_Status_Template t,nrmdb.tau_user u
where u.user_id=t.owner_id and template_id=#{id}

select count(*) num from (select * from (select d1.value title_text, d2.value object_class, d3.value professional_type, e1.description, e1.flow_img, e1.item_id, e1.vendor_id vendor_id from tfp_adv_key_code d1, tfp_adv_key_code d2, tfp_adv_key_code d3, tfp_adv_matchcond f1, tfp_adv_matchcond f2, tfp_adv_matchcond f3, tfp_advice_item e1 where d1.condition_id = f1.condition_id and d2.condition_id = f2.condition_id and d3.condition_id = f3.condition_id and f1.field_name = 'title_text' and f2.field_name = 'object_class' and f3.field_name = 'professional_type' and d1.item_id = d2.item_id and d1.item_id = d3.item_id and d1.item_id = e1.item_id
and e1.vendor_id= ${vendorId}
and d2.value='${objectClass}'
and d3.value='${professionalType}'
and lower(d1.value) like '%${titleText}%'
) t left join tia_alarm_dict tia1 on t.object_class = to_char(tia1.id) and tia1.type = 9 left join tia_alarm_dict tia2 on t.professional_type = to_char(tia2.id) and tia2.type = 1001 left join nrmdb.vendor_name tia3 on t.vendor_id = tia3.type)

select t.item_id, t.title_text, DBMS_LOB.substr(t.description, 6000, 1) as DESCRIPTION, tia3.zh_name vendor, tia2.txt professional, tia1.txt objectclass, t.vendor_id, t.professional_type, t.object_class, t.flow_img flow_img, t.flow_img flow_img_link from (select row_number() over(order by e1.item_id desc) arownum, d1.value title_text, d2.value object_class, d3.value professional_type, e1.description , e1.flow_img, e1.item_id, e1.vendor_id vendor_id from tfp_adv_key_code d1, tfp_adv_key_code d2, tfp_adv_key_code d3, tfp_adv_matchcond f1, tfp_adv_matchcond f2, tfp_adv_matchcond f3, tfp_advice_item e1 where d1.condition_id = f1.condition_id and d2.condition_id = f2.condition_id and d3.condition_id = f3.condition_id and f1.field_name = 'title_text' and f2.field_name = 'object_class' and f3.field_name = 'professional_type' and d1.item_id = d2.item_id and d1.item_id = d3.item_id and d1.item_id = e1.item_id
and e1.vendor_id= ${vendorId}
and d2.value='${objectClass}'
and d3.value='${professionalType}'
and lower(d1.value) like '%${titleText}%'
) t left join tia_alarm_dict tia1 on t.object_class = to_char(tia1.id) and tia1.type = 9 left join tia_alarm_dict tia2 on t.professional_type = to_char(tia2.id) and tia2.type = 1001 left join vendor_name tia3 on t.vendor_id = tia3.type


select t.* from standard_roster_column t
where professional_type=${profType} and ne_type=${neType} and vendor_id=${vendType}
order by col_index


select * from
(select * from standard_roster_record
where professional_type = ${professional_type}
and vendor_id = ${vendor_id}
and ne_type = ${ne_type}
and org_type = ${org_type}
order by import_time desc)
where rownum < 2


select * from
(select * from standard_roster_record
where professional_type = ${professional_type}
and vendor_id = ${vendor_id}
and org_type = ${org_type}
order by import_time desc)
where rownum < 2


select rownum,t.* from(
select 'Current' as temporaryfiletype,${v0} from standard_roster_content
where roster_int_id=${v1}
union all
select 'Pre' as  temporaryfiletype,${v0} from standard_roster_content
where roster_int_id=${v2}
union all
select 'Enable' as  temporaryfiletype,${v0} from standard_roster_content
where roster_int_id=${v3}
order by ${v0}) t

