select distinct standard_alarm_id txt,info_id id FROM tfm_alarm_stand_info  
where standard_alarm_id is not null and vendor_id=${v0} and eqp_object_class=${v1} 
and standard_alarm_id like lower('%${v2}%')


select distinct standard_alarm_id txt,info_id id FROM tfm_alarm_stand_info  
where standard_alarm_id is not null and vendor_id=${v0} and object_class=${v1} 
and standard_alarm_id like lower('%${v2}%')


select ser_file_id id,Relation_type,rule_name,file_name,new_file,opt_person,change_time,in_use,ruledesc,professional_type,RULE_DEF_USER 
from tfa_gaia_rule_file where lower(rule_name) like lower('%${v0}%') and in_use in (${v1}) and professional_type in (${v2}) 
order by change_time ${v3}

mapper.update:

update tfa_gaia_rule_file set  rule_name='${v1}', change_time=STR_TO_DATE('${v2}','%Y-%m-%d %T'), ruledesc='${v3}'
, directorys='' ,file_name='${v1}.xml',opt_person='${v5}',new_file='new',in_use=${v6},alarm_id_num=0,RULE_DEF_USER='${v7}'
,RULE_DEF_PHONE='${v8}',RELATION_TYPE=${v9}, professional_type=${v10},active_time_out='${v11}m',thresh_hold=${v12}
,project_surpress=${v13},relation_name='${v14}',change_status=1,whitelist_province='${v15}',blacklist_province='${v16}'  
where ser_file_id=${v0}

