select count(*) total
  from (select t1.group_id,
               t1.group_name,
               t2.group_type_name,
               t2.group_type_id,
               row_number() over(order by t1.group_type_id) rownumber
          from tai_group_info t1, tai_group_type t2
         where t1.group_type_id = t2.group_type_id
           and t1.group_type_id = #{groupTypeId}
           )

select t.item_id, t.title_text, t.description, tia3.zh_name vendor, tia2.txt professional, tia1.txt objectclass, t.vendor_id, t.professional_type, t.object_class, t.flow_img flow_img, t.flow_img flow_img_link from (select row_number() over(order by e1.item_id desc) arownum, d1.value title_text, d2.value object_class, d3.value professional_type, e1.description, e1.flow_img, e1.item_id, e1.vendor_id vendor_id from tfp_adv_key_code d1, tfp_adv_key_code d2, tfp_adv_key_code d3, tfp_adv_matchcond f1, tfp_adv_matchcond f2, tfp_adv_matchcond f3, tfp_advice_item e1 where d1.condition_id = f1.condition_id and d2.condition_id = f2.condition_id and d3.condition_id = f3.condition_id and f1.field_name = 'title_text' and f2.field_name = 'object_class' and f3.field_name = 'professional_type' and d1.item_id = d2.item_id and d1.item_id = d3.item_id and d1.item_id = e1.item_id
and e1.vendor_id= ${vendorId}
and d2.value='${objectClass}'
and d3.value='${professionalType}'
and lower(d1.value) like '%${titleText}%'
) t left join tia_alarm_dict tia1 on t.object_class = to_char(tia1.id) and tia1.type = 9 left join tia_alarm_dict tia2 on t.professional_type = to_char(tia2.id) and tia2.type = 1001 left join vendor_name tia3 on t.vendor_id = tia3.type
